// scripts/tests/units/privaty.test.ts
//
// BLIND per-unit kit spec — privaty (AR / Water / Attacker / Burst III), written from kit prose ONLY.
// Blind to the driver's override/tests/reasoning. Convergence with the driver's tests is the signal.
//
// KIT (ground truth):
//   skill1  ■ "Entering Full Burst" → ALL ALLIES, 10s:
//             ATK ▲23.61% · Reload Speed ▲51.16% · Max Ammo ▼50.66% · Attack Damage ▲20.16%
//   skill2  ■ "last bullet hits the target" → the target (enemy), 10s:
//             Damage Taken ▲10.01% (boss debuff) ; +256.17% final-ATK additional damage   (ALWAYS)
//           ■ "last bullet hits a target in Designated Target status":
//             +1687% final-ATK additional damage                                              (GATED)
//   burst   ■ self, 10s: Elemental-Advantage Attack Damage ▲130%
//           ■ all enemies: 1407.64% final-ATK Burst-Skill damage · Stun 3s ·
//             applies "Designated Target" (ATK ▼5.02% for 10s on the boss)
//
// FIXTURE: controlComp('privaty', true). liter B1 / crown B2 / privaty B3 (carry, focus) / helm B3 supply a
// real Full-Burst chain (a lone B3 casts ZERO Full Bursts). Boss element is Fire; Privaty is Water, so she
// holds elemental advantage and the burst's elemAdvantage buff is live. Deterministic (no seed).
//
// TRIGGER READINGS (the 4 questions):
//   skill1: trigger = fullBurstEnter ("entering Full Burst" → fires on ANY team FB, not burst-cast); target
//           = allies ("all allies", includes self); durations = wall-clock 10s. Max-Ammo line is a DEBUFF
//           (negative) that shrinks magazines → raises last-bullet frequency (weapon-state = damage).
//   skill2: trigger = lastBullet (per-magazine); target = the enemy. Block A always; Block B additionally
//           requires the "Designated Target" status the BURST applies (requiresTargetStatus gate). Riders are
//           instant flatDamage, take FB by timing (no core — text says "additional damage", not core strike).
//   burst : self elemAdvantage buff (burst-cast, self only); 1407.64% is Burst-Skill damage → burst-cast
//           instant, FB-EXEMPT (lands before the FB window opens); stun + boss ATK▼ are inert in v1.
//
// ⚑ flags (outside the input domain): fire cadence / last-bullet timing rides the datamine-unreliable
//   rate_of_fire + the maxAmmo▼ magazine — trigger IDENTITY is certain, its wall-clock CADENCE is not.

import { describe, it, expect } from 'vitest';
import { controlComp, runComp, withPatchedOverride } from '../lib/harness';

type Ev = any;

// Threads a patched in-memory override into runComp (mirrors the helm exemplar's counterfactual wiring;
// committed JSON is never touched). Collects the full event log via cfg.onEvent.
function run(patch?: (o: any) => void) {
  const opts: any = controlComp('privaty', true);
  const events: Ev[] = [];
  opts.cfg = { ...(opts.cfg ?? {}), onEvent: (ev: Ev) => events.push(ev) };
  if (patch) opts.overrides = { ...(opts.overrides ?? {}), privaty: withPatchedOverride('privaty', patch) };
  const res = runComp(opts);
  return { res, events };
}

const near = (a: number, b: number, eps = 0.05) => Math.abs(a - b) <= eps;
const buffApplies = (evs: Ev[], stat: string) => evs.filter(e => e.kind === 'buffApply' && e.stat === stat);
const dmgMult = (evs: Ev[], mult: number, eps = 0.05) =>
  evs.filter(e => e.kind === 'damage' && near(e.mult, mult, eps));

// content-addressed mutators (blind to block indexing — search by stat/value/kind)
function scopeBlock(o: any, stat: string, val: number, target: any) {
  for (const b of o.blocks ?? [])
    if ((b.effects ?? []).some((e: any) => e.stat === stat && near(e.value, val, 0.1))) b.target = target;
}
function zeroFlat(o: any, atkPct: number) {
  for (const b of o.blocks ?? [])
    for (const e of b.effects ?? []) if (e.kind === 'flatDamage' && near(e.atkPct, atkPct, 0.5)) e.atkPct = 0;
}
function killTargetStatus(o: any) {
  for (const b of o.blocks ?? [])
    for (const e of b.effects ?? []) if (e.kind === 'targetStatus') e.durationSec = 0;
}

// One faithful 180s run drives most assertions; counterfactuals are hoisted so each is a single sim.
const base = run();
const selfScopedS1 = run(o => scopeBlock(o, 'atkPct', 23.61, { kind: 'self' }));
const alliesScopedElem = run(o => scopeBlock(o, 'elemAdvantageDamagePct', 130, { kind: 'allies' }));
const noRider256 = run(o => zeroFlat(o, 256.17));
const noStatus = run(killTargetStatus);

describe('privaty — fixture sanity', () => {
  it('the comp chains Full Bursts and Privaty casts her burst (else every trigger is vacuous)', () => {
    expect(base.events.filter(e => e.kind === 'fullBurstStart').length).toBeGreaterThan(0);
    expect(base.events.filter(e => e.kind === 'burstCast').length).toBeGreaterThan(0);
  });
});

describe('privaty — skill1 (Full-Burst-enter team buffs)', () => {
  it('ATK ▲23.61% applies to ALL 4 allies (incl self) on FB enter', () => {
    const mine = buffApplies(base.events, 'atkPct').filter(e => near(e.value, 23.61));
    expect(mine.length).toBeGreaterThan(0);
    expect(new Set(mine.map(e => e.targetIdx)).size).toBe(4); // faithful: whole team
  });

  it('ATK buff is ALLIES-scoped, not self (RED under a self-scoped model)', () => {
    const slots = new Set(
      buffApplies(selfScopedS1.events, 'atkPct').filter(e => near(e.value, 23.61)).map(e => e.targetIdx),
    );
    expect(slots.size).toBe(1); // nearest-wrong collapses 4 targets → 1
  });

  it('keys to Full-Burst ENTER (one application round per team FB), not burst-cast', () => {
    const fbs = base.events.filter(e => e.kind === 'fullBurstStart').length;
    const rounds = buffApplies(base.events, 'atkPct').filter(e => near(e.value, 23.61)).length / 4;
    expect(rounds).toBe(fbs);
  });

  it('Reload Speed ▲51.16% applies to all 4 allies', () => {
    const mine = buffApplies(base.events, 'reloadSpeedPct').filter(e => near(e.value, 51.16));
    expect(mine.length).toBeGreaterThan(0);
    expect(new Set(mine.map(e => e.targetIdx)).size).toBe(4);
  });

  it('Max Ammunition ▼50.66% is a DEBUFF (negative) on all allies — shrinks magazines', () => {
    const mine = buffApplies(base.events, 'maxAmmoPct').filter(e => near(e.value, -50.66, 0.1));
    expect(mine.length).toBeGreaterThan(0);
    for (const e of mine) expect(e.value).toBeLessThan(0); // RED if modeled as a positive buff
    expect(new Set(mine.map(e => e.targetIdx)).size).toBe(4);
  });

  it('Attack Damage ▲20.16% (Damage-Up bucket) applies to all allies', () => {
    const mine = buffApplies(base.events, 'attackDamagePct').filter(e => near(e.value, 20.16));
    expect(mine.length).toBeGreaterThan(0);
    expect(new Set(mine.map(e => e.targetIdx)).size).toBe(4);
  });
});

describe('privaty — skill2 (last-bullet riders)', () => {
  it('Damage Taken ▲10.01% is a BOSS debuff (caster/target null), fired per last-bullet', () => {
    const mine = buffApplies(base.events, 'damageTakenPct').filter(e => near(e.value, 10.01));
    expect(mine.length).toBeGreaterThan(0);
    for (const e of mine) {
      expect(e.casterIdx).toBeNull(); // boss-held debuff signature
      expect(e.targetIdx).toBeNull();
    }
  });

  it('ALWAYS rider deals +256.17% final-ATK additional damage', () => {
    expect(dmgMult(base.events, 2.5617, 0.02).length).toBeGreaterThan(0);
    expect(dmgMult(noRider256.events, 2.5617, 0.02).length).toBe(0); // RED when the rider is zeroed
  });

  it('+1687% rider is GATED on the burst-applied "Designated Target" status (non-vacuity: both cases)', () => {
    // active case: burst opens the status → the big rider fires
    expect(dmgMult(base.events, 16.87, 0.05).length).toBeGreaterThan(0);
    // inactive case: strip the burst's targetStatus → the gate never opens → rider silent
    expect(dmgMult(noStatus.events, 16.87, 0.05).length).toBe(0);
    // inertness: the ALWAYS 256.17% rider is unaffected by the status being gone
    expect(dmgMult(noStatus.events, 2.5617, 0.02).length).toBeGreaterThan(0);
  });
});

describe('privaty — burst', () => {
  it('Elemental-Advantage Attack Damage ▲130% is SELF-only', () => {
    const mine = buffApplies(base.events, 'elemAdvantageDamagePct').filter(e => near(e.value, 130, 0.2));
    expect(mine.length).toBeGreaterThan(0);
    expect(new Set(mine.map(e => e.targetIdx)).size).toBe(1); // self only
  });

  it('elemAdvantage buff is self, not allies (RED under an allies-scoped model)', () => {
    const slots = new Set(
      buffApplies(alliesScopedElem.events, 'elemAdvantageDamagePct')
        .filter(e => near(e.value, 130, 0.2))
        .map(e => e.targetIdx),
    );
    expect(slots.size).toBe(4); // nearest-wrong spreads a self buff to the team
  });

  it('1407.64% Burst-Skill damage lands FB-EXEMPT (no +50% Full-Burst major)', () => {
    const hits = dmgMult(base.events, 14.0764, 0.1);
    expect(hits.length).toBeGreaterThan(0);
    for (const e of hits) expect(e.fbMajorApplied).toBe(false); // burst-cast instant precedes the FB window
  });

  // GAP: Stun 3s — the v1 boss never fires/charges/reloads, so a stun has no observable effect.
  it.skip('burst stuns the boss for 3s (unobservable: boss takes no actions in v1)', () => {});

  // GAP: Designated Target ATK ▼5.02% — boss ATK does not feed our damage (immortal, deals no damage).
  it.skip('Designated Target ATK ▼5.02% (inert: boss ATK never affects our output in v1)', () => {});
});
